// Use a simple but complete QR code library approach
// Since we can't download it, use an iframe-based approach or canvas-drawn placeholder
// that still shows the URL prominently

// Override with simpler approach: use Google Charts API as primary, canvas fallback
global.QRCode = function(el, opts) {
  var url = typeof opts === 'string' ? opts : opts.text;
  var size = (opts && opts.width) || 256;
  var img = document.createElement('img');
  // Use multiple QR API sources with fallback
  var apis = [
    'https://api.qrserver.com/v1/create-qr-code/?size='+size+'x'+size+'&data=',
    'https://chart.googleapis.com/chart?chs='+size+'x'+size+'&cht=qr&chl=',
  ];
  var tried = 0;
  function tryNext() {
    if (tried >= apis.length) {
      // All APIs failed — show text link
      el.innerHTML = '<div style="text-align:center;padding:10px;word-break:break-all;font-size:11px;color:#333">'
        + '<div style="margin-bottom:8px;font-size:13px;font-weight:bold">📲 掃描網址</div>'
        + '<a href="'+url+'" target="_blank" style="color:#06C755">'+url+'</a></div>';
      return;
    }
    var src = apis[tried++] + encodeURIComponent(url);
    img.onload = function() {
      el.innerHTML = '';
      img.style.cssText = 'width:'+size+'px;height:'+size+'px;display:block;margin:0 auto;border-radius:4px;background:#fff';
      el.appendChild(img);
    };
    img.onerror = tryNext;
    img.src = src;
  }
  img.crossOrigin = 'anonymous';
  tryNext();
  // Store reference for canvas download
  el._qrImg = img;
  el._qrUrl = url;
};
